request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?message ?messageName
WHERE {
  ?model a bboExt:Model ;
         tai:originalId "6c9090aeef814120944b4885c7343b63" .
  ?definitions tai:belongsTo ?model .
  ?choreo tai:belongsTo ?definitions .
  ?message a bboExt:Message ;
           tai:belongsTo ?choreo .
  OPTIONAL { ?message bbo:name ?messageName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?id ?normalizedId ?originalId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  FILTER(CONTAINS(STR(?originalId), "6c9090aeef814120944b4885c7343b63") || CONTAINS(STR(?normalizedId), "6c9090aeef814120944b4885c7343b63"))
}
LIMIT 25
